// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract MockENSRegistry {
    mapping(bytes32 => address) public resolver;

    function setResolver(bytes32 node, address resolverAddr) external {
        resolver[node] = resolverAddr;
    }
}

contract MockResolver {
    mapping(bytes32 => address) public addr;

    function setAddr(bytes32 node, address a) external {
        addr[node] = a;
    }
}

contract ENSLookup {
    error NoResolver();
    error NoAddress();

    address public registry;

    constructor(address _registry) {
        registry = _registry;
    }

    function resolve(bytes32 node) external view returns (address) {
        MockENSRegistry reg = MockENSRegistry(registry);
        address resolverAddr = [[SLOT reg_lookup]];
        if ([[SLOT null_check]]) revert NoResolver();

        MockResolver res = MockResolver(resolverAddr);
        address result = [[SLOT addr_lookup]];
        if (result == address(0)) revert NoAddress();

        return result;
    }
}
